import sqlite3
import os
import math

def get_hex_neighbors(x, y):
    if y % 2 == 1:
        return [(x+1, y), (x+1, y-1), (x+1, y+1), (x-1, y), (x, y-1), (x, y+1)]
    else:
        return [(x+1, y), (x, y-1), (x, y+1), (x-1, y), (x-1, y-1), (x-1, y+1)]

def hex_distance(x1, y1, x2, y2):
    def to_cube(x, y):
        if y % 2 == 1:
            x_cube = x - (y - 1) // 2
        else:
            x_cube = x - y // 2
        return x_cube, y, -x_cube - y
    cx1, cy1, cz1 = to_cube(x1, y1)
    cx2, cy2, cz2 = to_cube(x2, y2)
    return max(abs(cx1 - cx2), abs(cy1 - cy2), abs(cz1 - cz2))

dbpath = None
for f in os.listdir('/data/maps'):
    fp = '/data/maps/' + f
    if os.path.getsize(fp) > 0:
        dbpath = fp
        break

conn = sqlite3.connect(dbpath)
cursor = conn.cursor()
cursor.execute("SELECT * FROM Map LIMIT 1")
map_row = cursor.fetchone()
_, width, height = map_row[0], map_row[1], map_row[2]

cursor.execute("SELECT * FROM Plots ORDER BY ID")
plots = {}
for row in cursor.fetchall():
    pid, terrain, continent, impassable = row
    x, y = pid % width, pid // width
    plots[(x, y)] = {'terrain': terrain, 'impassable': bool(impassable)}

cursor.execute("SELECT * FROM PlotFeatures")
for row in cursor.fetchall():
    pid, feature = row
    x, y = pid % width, pid // width
    if (x, y) in plots:
        plots[(x, y)]['feature'] = feature

cursor.execute("SELECT * FROM PlotRivers")
for row in cursor.fetchall():
    pid = row[0]
    x, y = pid % width, pid // width
    if (x, y) in plots:
        plots[(x, y)]['has_river'] = True

def calc_campus(x, y):
    n = get_hex_neighbors(x, y)
    geo = sum(1 for t in n if t in plots and plots[t].get('feature') == 'FEATURE_GEOTHERMAL_FISSURE')
    reef = sum(1 for t in n if t in plots and plots[t].get('feature') == 'FEATURE_REEF')
    mtn = sum(1 for t in n if t in plots and plots[t].get('terrain') == 'TERRAIN_GRASS_MOUNTAIN')
    rain = sum(1 for t in n if t in plots and plots[t].get('feature') in ['FEATURE_JUNGLE', 'FEATURE_RAINFOREST'])
    return geo*2 + reef*2 + mtn*1 + sum(math.floor(0.5) for _ in range(rain))

def calc_commercial(x, y):
    tile = plots.get((x, y), {})
    has_river = tile.get('has_river', False)
    n = get_hex_neighbors(x, y)
    has_harbor = any(t in plots and plots[t].get('terrain') == 'TERRAIN_COAST' for t in n)
    return (2 if has_river else 0) + (2 if has_harbor else 0)

def calc_industrial(x, y):
    n = get_hex_neighbors(x, y)
    forest = sum(1 for t in n if t in plots and plots[t].get('feature') == 'FEATURE_FOREST')
    return sum(math.floor(0.5) for _ in range(forest))

def calc_theater(x, y):
    n = get_hex_neighbors(x, y)
    entertainment = sum(1 for t in n if t in plots and plots[t].get('terrain') == 'TERRAIN_COAST')
    return sum(math.floor(0.5) for _ in range(entertainment))

# Main landmass valid tiles
valid_tiles = [(x, y) for (x, y) in plots if 19 <= x <= 27 and 11 <= y <= 17]
valid_tiles = [t for t in valid_tiles if plots[t]['terrain'] not in ['TERRAIN_OCEAN', 'TERRAIN_GRASS_MOUNTAIN']]
valid_tiles = [t for t in valid_tiles if plots[t].get('feature') != 'FEATURE_GEOTHERMAL_FISSURE']

best = (0, None)
for cc in valid_tiles:
    # Find all valid district placements within 3 range
    reachable = []
    for t in valid_tiles:
        if hex_distance(cc[0], cc[1], t[0], t[1]) <= 3 and t != cc:
            reachable.append(t)

    # Score each
    scores = []
    for t in reachable:
        c = calc_campus(t[0], t[1])
        o = calc_commercial(t[0], t[1])
        i = calc_industrial(t[0], t[1])
        scores.append(('CAMPUS', t, c))
        scores.append(('COMMERCIAL_HUB', t, o))
        scores.append(('INDUSTRIAL_ZONE', t, i))

    scores.sort(key=lambda x: -x[2])

    # Try combinations
    chosen = []
    used_types = set()
    used_tiles = set()
    for s in scores:
        if s[0] not in used_types and s[1] not in used_tiles:
            chosen.append(s)
            used_types.add(s[0])
            used_tiles.add(s[1])
            if len(chosen) >= 3:
                break

    total = sum(s[2] for s in chosen)
    if total > best[0]:
        best = (total, cc, chosen)

print(f"Best: {best[0]} at {best[1]}")
for s in best[2]:
    print(f"  {s[0]} at {s[1]}: {s[2]}")
